<section class="admin-page-head"><div><p class="eyebrow">CMS / PAGINĂ</p><h1><?= e($page['title']) ?></h1><p>/<?= e($page['slug']) ?></p></div><a class="admin-button secondary" href="<?= e(url('/admin/cms')) ?>">Înapoi</a></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><form class="admin-form-layout" method="post" action="<?= e(url('/admin/cms/pagini/'.$page['id'])) ?>"><?= csrf_field() ?><div><section class="admin-panel"><h2>Conținut</h2><label>Titlu<input name="title" required value="<?= e($page['title']) ?>"></label><label>HTML sigur<textarea name="content_html" rows="20"><?= e($page['content_html']) ?></textarea></label></section><section class="admin-panel"><h2>SEO</h2><label>Meta title<input name="meta_title" value="<?= e($page['meta_title']) ?>"></label><label>Meta description<textarea name="meta_description"><?= e($page['meta_description']) ?></textarea></label></section></div><aside><section class="admin-panel"><h2>Publicare</h2><label>Status<select name="status"><?php foreach(['draft','published','archived'] as $status): ?><option <?= $page['status']===$status?'selected':'' ?>><?= e($status) ?></option><?php endforeach; ?></select></label><label class="check-label"><input type="checkbox" name="robots_index" value="1" <?= $page['robots_index']?'checked':'' ?>> Index, follow</label><button class="admin-button" type="submit">Salvează pagina</button></section></aside></form>
